  "sourcesContent": [".page { display:flex;flex-direction:column;gap:24px; }\r\n.page-header { display:flex;align-items:flex-start;justify-content:space-between;flex-wrap:wrap;gap:12px; }\r\n.page-sub { color:var(--text-secondary);margin-top:4px; }\r\n.tabs { display:flex;gap:8px; }\r\n.tab { padding:8px 18px;border-radius:var(--radius-sm);font-size:13px;font-weight:600;border:none;cursor:pointer;background:white;color:var(--text-secondary);border:1px solid var(--border);transition:all 0.15s; }\r\n.tab.active { background:var(--orange);color:white;border-color:var(--orange); }\r\n.grid { display:grid;grid-template-columns:repeat(auto-fill,minmax(260px,1fr));gap:16px; }\r\n.card { padding:20px;background:white;border-radius:var(--radius-lg);border:1px solid var(--border);transition:all 0.2s;box-shadow:var(--shadow-card); }\r\n.card:hover { box-shadow:var(--shadow-hover);transform:translateY(-2px); }\r\n.talent-header { display:flex;align-items:center;gap:12px;margin-bottom:14px;flex-wrap:wrap; }\r\n.talent-avatar { width:40px;height:40px;border-radius:11px;background:linear-gradient(135deg,#E8622A,#FF9A5C);color:white;display:flex;align-items:center;justify-content:center;font-weight:700;font-size:16px;flex-shrink:0; }\r\n.card-name { font-family:\"Plus Jakarta Sans\",sans-serif;font-size:14px;font-weight:700;margin-bottom:2px; }\r\n.card-meta { font-size:12px;color:var(--text-secondary); }\r\n.skills { display:flex;flex-wrap:wrap;gap:6px; }\r\n.skill-tag { padding:3px 10px;background:var(--orange-light);color:var(--orange);border-radius:99px;font-size:11px;font-weight:600; }\r\n.score-badge { background:linear-gradient(135deg,var(--orange),#FF9A5C);color:white;padding:4px 10px;border-radius:99px;font-size:11px;font-weight:700; }\r\n"],
