ap: wrap;\r\n  gap: 8px;\r\n  margin-top: 16px;\r\n}\r\n.tm-chip {\r\n  display: inline-flex;\r\n  align-items: center;\r\n  gap: 6px;\r\n  padding: 6px 12px;\r\n  border-radius: 999px;\r\n  font-size: 13px;\r\n  color: var(--text-secondary);\r\n  background: rgba(255, 255, 255, 0.85);\r\n  border: 1px solid var(--border);\r\n}\r\n.tm-chip strong { color: var(--text-main); font-weight: 700; }\r\n.tm-hero__panel {\r\n  padding: 18px;\r\n  border-radius: var(--radius-md);\r\n  background: rgba(255, 255, 255, 0.9);\r\n  border: 1px solid rgba(29, 158, 117, 0.18);\r\n  box-shadow: var(--shadow-card);\r\n}\r\n.tm-hero__panel-title {\r\n  margin: 0 0 12px;\r\n  font-size: 12px;\r\n  font-weight: 700;\r\n  text-transform: uppercase;\r\n  letter-spacing: 0.06em;\r\n  color: var(--text-secondary);\r\n}\r\n.tm-hero__btn { width: 100%; justify-content: center; }\r\n.tm-hero__btn + .tm-hero__btn { margin-top: 8px; }\r\n\r\n.tm-form--edit {\r\n  border-left: 4px solid var(--teal);\r\n}\r\n\r\n.tm-tabs {\r\n  width: 100%;\r\n  max-width: 100%;\r\n  box-shadow: 0 1px 2px rgba(0, 0, 0, 0.04);\r\n}\r\n\r\n.listing-card__head {\r\n  display: flex;\r\n  justify-content: space-between;\r\n  align-items: center;\r\n  margin-bottom: 14px;\r\n}\r\n.listing-card__footer {\r\n  margin-top: 14px;\r\n  padding-top: 12px;\r\n  border-top: 1px solid var(--border);\r\n}\r\n\r\n/* \u2500\u2500 ALERTS \u2500\u2500 */\r\n.kh-alert {\r\n  display: flex;\r\n  align-items: center;\r\n  gap: 10px;\r\n  padding: 12px 16px;\r\n  border-radius: var(--radius-md);\r\n  font-size: 14px;\r\n  font-weight: 500;\r\n  margin-bottom: 20px;\r\n}\r\n.kh-alert--success { background: var(--teal-light); color: var(--teal-dark); border: 1px solid var(--teal-mid); }\r\n.kh-alert--danger  { background: var(--danger-bg);  color: var(--danger-text); border: 1px solid var(--danger-border); }\r\n\r\n/* \u2500\u2500 PAGE HEADER \u2500\u2500 */\r\n.page-header {\r\n  display: flex;\r\n  align-items: flex-start;\r\n  justify-content: space-between;\r\n  gap: 16px;\r\n  flex-wrap: wrap;\r\n  margin-bottom: 28px;\r\n}\r\n.kh-page-title { font-size: 26px; font-weight: 600; letter-spacing: -0.4px; margin-bottom: 4px; }\r\n.page-sub      { font-size: 14px; color: var(--text-secondary); }\r\n\r\n/* \u2500\u2500 BUTTONS \u2500\u2500 */\r\n.kh-btn {\r\n  display: inline-flex;\r\n  align-items: center;\r\n  justify-content: center;\r\n  gap: 6px;\r\n  padding: 10px 20px;\r\n  border-radius: var(--radius-md);\r\n  font-size: 14px;\r\n  font-weight: 500;\r\n  font-family: 'Plus Jakarta Sans', 'Inter', system-ui, sans-serif;\r\n  cursor: pointer;\r\n  border: 1px solid var(--border);\r\n  background: var(--bg-card);\r\n  color: var(--text-main);\r\n  transition: all 0.18s ease;\r\n  white-space: nowrap;\r\n}\r\n.kh-btn:hover            { background: var(--bg-surface); }\r\n.kh-btn--primary         { background: var(--teal); color: #fff; border-color: var(--teal); }\r\n.kh-btn--primary:hover   { background: var(--teal-dark); border-color: var(--teal-dark); }\r\n.kh-btn--primary:disabled{ opacity: .6; cursor: not-allowed; }\r\n.kh-btn--ghost           { background: var(--bg-surface); color: var(--text-secondary); border-color: transparent; }\r\n.kh-btn--ghost:hover     { background: #e2e8f0; color: var(--text-main); }\r\n.kh-btn--sm              { padding: 7px 14px; font-size: 13px; }\r\n.w-full                  { width: 100%; }\r\n\r\n/* \u2500\u2500 FORM PANEL \u2500\u2500 */\r\n.form-panel {\r\n  background: var(--bg-card);\r\n  border: 1px solid var(--border);\r\n  border-radius: var(--radius-lg);\r\n  padding: 24px;\r\n  margin-bottom: 24px;\r\n  box-shadow: var(--shadow-card);\r\n}\r\n.form-panel__header {\r\n  display: flex;\r\n  align-items: center;\r\n  justify-content: space-between;\r\n  margin-bottom: 20px;\r\n}\r\n.form-panel__header h3 { font-size: 16px; font-weight: 600; }\r\n.form-row   { display: grid; grid-template-columns: 1fr 1fr; gap: 14px; margin-bottom: 14px; }\r\n.form-group { display: flex; flex-direction: column; }\r\n.form-group label { font-size: 13px; font-weight: 500; color: var(--text-secondary); margin-bottom: 6px; }\r\n.form-hint  { font-weight: 400; color: var(--text-muted); }\r\n.kh-input {\r\n  width: 100%;\r\n  padding: 10px 13px;\r\n  border: 1px solid var(--border);\r\n  border-radius: var(--radius-sm);\r\n  font-size: 14px;\r\n  font-family: 'Plus Jakarta Sans', 'Inter', system-ui, sans-serif;\r\n  background: var(--bg-card);\r\n  color: var(--text-main);\r\n  outline: none;\r\n  transition: border-color .15s, box-shadow .15s;\r\n}\r\n.kh-input:focus       { border-color: var(--teal); box-shadow: 0 0 0 3px rgba(29,158,117,.12); }\r\n.kh-input::placeholder{ color: var(--text-muted); }\r\n\r\n/* \u2500\u2500 TABS \u2500\u2500 */\r\n.tabs {\r\n  display: flex;\r\n  gap: 4px;\r\n  margin-bottom: 24px;\r\n  background: var(--bg-surface);\r\n  padding: 4px;\r\n  border-radius: var(--radius-md);\r\n  border: 1px solid var(--border);\r\n  width: fit-content;\r\n}\r\n.tab {\r\n  padding: 8px 22px;\r\n  border-radius: 7px;\r\n  font-size: 14px;\r\n  font-weight: 500;\r\n  font-family: 'Plus Jakarta Sans', 'Inter', system-ui, sans-serif;\r\n  cursor: pointer;\r\n  border: none;\r\n  background: transparent;\r\n  color: var(--text-secondary);\r\n  transition: all .15s;\r\n}\r\n.tab.active         { background: var(--bg-card); color: var(--teal); border: 1px solid var(--border); }\r\n.tab:not(.active):hover { color: var(--text-main); }\r\n\r\n/* \u2500\u2500 GRID \u2500\u2500 */\r\n.grid { display: grid; grid-template-columns: repeat(auto-fill, minmax(290px, 1fr)); gap: 16px; }\r\n\r\n/* \u2500\u2500 CARD \u2500\u2500 */\r\n.card {\r\n  background: var(--bg-card);\r\n  border: 1px solid var(--border);\r\n  border-radius: var(--radius-lg);\r\n  padding: 20px;\r\n  box-shadow: var(--shadow-card);\r\n  transition: border-color .18s, box-shadow .18s, transform .18s;\r\n}\r\n.card:hover { border-color: var(--border-focus); box-shadow: var(--shadow-hover); transform: translateY(-2px); }\r\n.tm-page .card {\r\n  background: linear-gradient(180deg, #ffffff 0%, #fafbfc 100%);\r\n  border-color: rgba(15, 23, 42, 0.07);\r\n}\r\n.talent-card { display: flex; flex-direction: column; }\r\n\r\n/* \u2500\u2500 TALENT CARD INTERNALS \u2500\u2500 */\r\n.talent-header {\r\n  display: flex;\r\n  align-items: center;\r\n  gap: 12px;\r\n  margin-bottom: 10px;\r\n}\r\n.talent-avatar {\r\n  width: 42px; height: 42px; border-radius: 50%;\r\n  background: var(--teal-light);\r\n  display: flex; align-items: center; justify-content: center;\r\n  font-size: 15px; font-weight: 600; color: var(--teal-dark);\r\n  flex-shrink: 0;\r\n}\r\n.talent-info   { flex: 1; min-width: 0; }\r\n.card-name     { font-size: 15px; font-weight: 600; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }\r\n.card-meta     { font-size: 12px; color: var(--text-secondary); margin-top: 2px; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }\r\n.exp-badge {\r\n  display: inline-flex; align-items: center;\r\n  padding: 3px 10px;\r\n  background: var(--blue-bg); color: var(--blue-text);\r\n  border-radius: 20px; font-size: 12px; font-weight: 600;\r\n  width: fit-content; margin-bottom: 4px;\r\n}\r\n.talent-bio {\r\n  font-size: 12px; color: var(--text-secondary); margin-top: 10px; line-height: 1.6;\r\n  display: -webkit-box; -webkit-line-clamp: 2; -webkit-box-orient: vertical; overflow: hidden;\r\n}\r\n.card-footer {\r\n  display: flex; gap: 8px;\r\n  margin-top: auto; padding-top: 14px;\r\n  border-top: 1px solid var(--border);\r\n  margin-top: 14px;\r\n}\r\n\r\n/* \u2500\u2500 UTILITY \u2500\u2500 */\r\n.mt-6  { margin-top: 6px; }\r\n.mt-10 { margin-top: 10px; }\r\n.location-chip { font-size: 12px; color: var(--text-muted); margin-top: 8px; }\r\n\r\n/* \u2500\u2500 SKILLS \u2500\u2500 */\r\n.skills        { display: flex; flex-wrap: wrap; gap: 6px; }\r\n.skill-tag     { padding: 4px 11px; background: var(--bg-surface); color: var(--text-secondary); border-radius: 6px; font-size: 12px; font-weight: 500; }\r\n.skill-tag.success { background: var(--teal-light); color: var(--teal-dark); }\r\n.skill-tag.danger  { background: var(--danger-bg);  color: var(--danger-text); }\r\n\r\n/* \u2500\u2500 BADGES \u2500\u2500 */\r\n.kh-badge {\r\n  display: inline-flex; align-items: center;\r\n  padding: 3px 10px; border-radius: 20px; font-size: 12px; font-weight: 600;\r\n}\r\n.kh-badge--green  { background: var(--teal-light); color: var(--teal-dark); }\r\n.kh-badge--teal   { background: #e0f7fa; color: #00695c; }\r\n.kh-badge--orange { background: var(--amber-bg);   color: var(--amber-text); }\r\n.kh-badge--gray   { background: var(--bg-surface);  color: var(--text-secondary); }\r\n\r\n/* \u2500\u2500 ACTION ICONS \u2500\u2500 */\r\n.action-icons { display: flex; gap: 6px; align-items: center; }\r\n.icon {\r\n  width: 32px; height: 32px;\r\n  border-radius: var(--radius-sm);\r\n  border: 1px solid var(--border);\r\n  background: var(--bg-card);\r\n  display: flex; align-items: center; justify-content: center;\r\n  cursor: pointer; color: var(--text-secondary); font-size: 13px;\r\n  transition: all .15s; font-family: inherit;\r\n}\r\n.icon:hover        { background: var(--bg-surface); color: var(--text-main); }\r\n.icon.delete:hover { background: var(--danger-bg); color: var(--danger-text); border-color: var(--danger-border); }\r\n.icon.edit:hover   { background: var(--blue-bg);   color: var(--blue-text);  border-color: #B5D4F4; }\r\n\r\n/* \u2500\u2500 EMPTY STATE \u2500\u2500 */\r\n.empty-state { text-align: center; padding: 48px 20px; color: var(--text-secondary); font-size: 14px; grid-column: 1/-1; }\r\n.empty-icon  { font-size: 32px; margin-bottom: 12px; }\r\n\r\n/* \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\r\n   MODALS\r\n   \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 */\r\n.modal-backdrop {\r\n  position: fixed; inset: 0;\r\n  background: rgba(15,23,42,0.55);\r\n  backdrop-filter: blur(6px);\r\n  -webkit-backdrop-filter: blur(6px);\r\n  display: flex; align-items: center; justify-content: center;\r\n  z-index: 1000; padding: 20px;\r\n}\r\n\r\n.modal {\r\n  background: var(--bg-card);\r\n  border-radius: var(--radius-lg);\r\n  width: 100%; max-width: 560px;\r\n  border: 1px solid var(--border);\r\n  box-shadow: var(--shadow-modal);\r\n  animation: modalIn .25s cubic-bezier(.34,1.56,.64,1);\r\n  max-height: 90vh;\r\n  overflow-y: auto;\r\n}\r\n.modal-matching { max-width: 640px; }\r\n\r\n@keyframes modalIn {\r\n  from { transform: scale(.95) translateY(10px); opacity: 0; }\r\n  to   { transform: scale(1)   translateY(0);    opacity: 1; }\r\n}\r\n\r\n.modal-header {\r\n  display: flex; align-items: center; justify-content: space-between;\r\n  padding: 18px 22px;\r\n  border-bottom: 1px solid var(--border);\r\n  position: sticky; top: 0; background: var(--bg-card); z-index: 2;\r\n}\r\n.modal-header h3 { font-size: 16px; font-weight: 600; display: flex; align-items: center; gap: 8px; }\r\n\r\n.close-btn {\r\n  width: 30px; height: 30px; border-radius: 50%;\r\n  border: 1px solid var(--border); background: transparent;\r\n  cursor: pointer; display: flex; align-items: center; justify-content: center;\r\n  color: var(--text-secondary); font-size: 16px; transition: all .15s;\r\n}\r\n.close-btn:hover { background: var(--bg-surface); }\r\n.modal-loading   { padding: 32px; text-align: center; color: var(--text-secondary); font-size: 14px; }\r\n\r\n/* \u2500\u2500 PROFILE MODAL \u2500\u2500 */\r\n.profile-modal { max-width: 560px; }\r\n\r\n.profile-hero {\r\n  display: flex;\r\n  align-items: center;\r\n  gap: 16px;\r\n  padding: 24px 22px 20px;\r\n  border-bottom: 1px solid var(--border);\r\n}\r\n.avatar-xl {\r\n  width: 64px; height: 64px; border-radius: 50%;\r\n  background: var(--teal-light);\r\n  display: flex; align-items: center; justify-content: center;\r\n  font-size: 22px; font-weight: 600; color: var(--teal-dark);\r\n  flex-shrink: 0;\r\n}\r\n.profile-hero-info  { flex: 1; min-width: 0; }\r\n.profile-name       { font-size: 20px; font-weight: 600; }\r\n.profile-level      { font-size: 13px; color: var(--text-secondary); margin-top: 3px; }\r\n.profile-email      { font-size: 13px; color: var(--teal); margin-top: 2px; }\r\n\r\n.profile-body { padding: 20px 22px 26px; }\r\n\r\n/* Info grid \u2014 2 columns */\r\n.info-grid {\r\n  display: grid;\r\n  grid-template-columns: 1fr 1fr;\r\n  border: 1px solid var(--border);\r\n  border-radius: var(--radius-md);\r\n  overflow: hidden;\r\n  margin-bottom: 20px;\r\n}\r\n.info-item {\r\n  display: flex; flex-direction: column; gap: 3px;\r\n  padding: 12px 14px;\r\n  border-bottom: 1px solid var(--border);\r\n  background: var(--bg-card);\r\n}\r\n.info-item:nth-child(odd)  { border-right: 1px solid var(--border); }\r\n.info-item:last-child,\r\n.info-item:nth-last-child(2):nth-child(odd) { border-bottom: none; }\r\n.info-label { font-size: 11px; font-weight: 600; color: var(--text-secondary); text-transform: uppercase; letter-spacing: .4px; }\r\n.info-value { font-size: 14px; color: var(--text-main); }\r\n.info-link  { font-size: 14px; color: var(--teal); text-decoration: none; }\r\n.info-link:hover { text-decoration: underline; }\r\n\r\n/* Sections */\r\n.profile-section { margin-bottom: 18px; }\r\n.section-label   { font-size: 11px; font-weight: 600; color: var(--text-secondary); text-transform: uppercase; letter-spacing: .4px; margin-bottom: 8px; }\r\n.bio-text {\r\n  font-size: 14px; color: var(--text-secondary); line-height: 1.65;\r\n  padding: 14px; background: var(--bg-surface); border-radius: var(--radius-sm);\r\n}\r\n\r\n.profile-cta {\r\n  display: flex; gap: 10px; margin-top: 6px;\r\n  padding-top: 18px;\r\n  border-top: 1px solid var(--border);\r\n}\r\n\r\n/* \u2500\u2500 ANNONCE DETAILS PANEL \u2500\u2500 */\r\n.annonce-details-panel { padding: 16px 22px 18px; background: var(--bg-surface); }\r\n.annonce-meta-row { display: flex; flex-wrap: wrap; align-items: center; gap: 10px; }\r\n.meta-chip { font-size: 13px; color: var(--text-secondary); }\r\n.divider-line { border: none; border-top: 1px solid var(--border); margin: 0 22px; }\r\n\r\n/* \u2500\u2500 MATCHING LIST \u2500\u2500 */\r\n.matching-list { padding: 16px 22px 22px; }\r\n.match-card {\r\n  background: var(--bg-surface);\r\n  border: 1px solid var(--border);\r\n  border-radius: var(--radius-md);\r\n  padding: 16px; margin-bottom: 12px;\r\n  transition: border-color .15s;\r\n}\r\n.match-card:hover { border-color: var(--border-focus); }\r\n.match-header { display: flex; align-items: center; gap: 12px; margin-bottom: 10px; }\r\n.match-avatar {\r\n  width: 40px; height: 40px; border-radius: 50%;\r\n  background: var(--teal-light);\r\n  display: flex; align-items: center; justify-content: center;\r\n  font-size: 15px; font-weight: 600; color: var(--teal-dark); flex-shrink: 0;\r\n}\r\n.match-info      { flex: 1; }\r\n.match-info h4   { font-size: 14px; font-weight: 600; }\r\n.match-info .email { font-size: 12px; color: var(--text-secondary); margin-top: 2px; }\r\n.score-pill {\r\n  padding: 5px 13px; border-radius: 20px;\r\n  font-size: 14px; font-weight: 600; flex-shrink: 0;\r\n}\r\n.micro-label { font-size: 11px; font-weight: 600; color: var(--text-secondary); text-transform: uppercase; letter-spacing: .3px; }\r\n\r\n/* \u2500\u2500 SCORE BAR \u2500\u2500 */\r\n.score-bar-wrap { width: 100%; height: 5px; background: #e2e8f0; border-radius: 99px; overflow: hidden; margin-bottom: 2px; }\r\n.score-bar-fill { height: 100%; border-radius: 99px; transition: width .6s ease; }\r\n\r\n/* \u2500\u2500 ANIMATIONS \u2500\u2500 */\r\n.animate-1 { animation: fadeUp .3s ease both; }\r\n.animate-2 { animation: fadeUp .3s .05s ease both; }\r\n.animate-3 { animation: fadeUp .3s .10s ease both; }\r\n@keyframes fadeUp {\r\n  from { opacity: 0; transform: translateY(12px); }\r\n  to   { opacity: 1; transform: translateY(0); }\r\n}\r\n\r\n/* \u2500\u2500 RESPONSIVE \u2500\u2500 */\r\n@media (max-width: 600px) {\r\n  .page        { padding: 20px 16px; }\r\n  .page-header { flex-direction: column; }\r\n  .kh-page-title { font-size: 22px; }\r\n  .form-row    { grid-template-columns: 1fr; }\r\n  .info-grid   { grid-template-columns: 1fr; }\r\n  .info-item:nth-child(odd) { border-right: none; }\r\n  .profile-cta { flex-direction: column; }\r\n  .profile-hero { flex-wrap: wrap; }\r\n}\r\n.match-card {\r\n  position: relative;\r\n  z-index: 1;\r\n}\r\n\r\n.score-bar-wrap {\r\n  position: relative;\r\n  z-index: 0;\r\n}\r\nbutton {\r\n  position: relative;\r\n  z-index: 2;\r\n}\r\n\r\n/* \u2500\u2500 Annonce description in modal \u2500\u2500 */\r\n.annonce-desc {\r\n  margin-top: 10px;\r\n  font-size: 14px;\r\n  line-height: 1.55;\r\n  color: var(--text-secondary);\r\n}\r\n\r\n/* \u2500\u2500 Matching list header \u2500\u2500 */\r\n.matching-list__head {\r\n  display: flex;\r\n  align-items: center;\r\n  justify-content: space-between;\r\n  gap: 12px;\r\n  margin-bottom: 14px;\r\n}\r\n.matching-list__title {\r\n  font-size: 12px;\r\n  font-weight: 600;\r\n  color: var(--text-secondary);\r\n  text-transform: uppercase;\r\n  letter-spacing: 0.35px;\r\n  margin: 0;\r\n}\r\n.matching-count {\r\n  font-size: 12px;\r\n  font-weight: 600;\r\n  color: var(--teal);\r\n  background: var(--teal-light);\r\n  padding: 4px 10px;\r\n  border-radius: 999px;\r\n}\r\n\r\n.modal-loading--pulse {\r\n  animation: pulseText 1.2s ease-in-out infinite;\r\n}\r\n@keyframes pulseText {\r\n  0%, 100% { opacity: 0.55; }\r\n  50% { opacity: 1; }\r\n}\r\n\r\n.modal-empty {\r\n  padding: 28px 16px;\r\n  text-align: center;\r\n  border: 1px dashed var(--border);\r\n  border-radius: var(--radius-md);\r\n  background: var(--bg-card);\r\n  margin-bottom: 8px;\r\n}\r\n.modal-empty__title {\r\n  margin: 0 0 6px;\r\n  font-size: 15px;\r\n  font-weight: 600;\r\n  color: var(--text-main);\r\n}\r\n.modal-empty__hint {\r\n  margin: 0;\r\n  font-size: 13px;\r\n  color: var(--text-muted);\r\n  line-height: 1.5;\r\n}\r\n\r\n/* \u2500\u2500 Modern match row \u2500\u2500 */\r\n.match-card--modern {\r\n  background: linear-gradient(135deg, var(--bg-card) 0%, var(--bg-surface) 100%);\r\n  border: 1px solid var(--border);\r\n  box-shadow: var(--shadow-card);\r\n  overflow: hidden;\r\n}\r\n.match-card--modern::before {\r\n  content: '';\r\n  position: absolute;\r\n  left: 0;\r\n  top: 0;\r\n  bottom: 0;\r\n  width: 3px;\r\n  background: linear-gradient(180deg, var(--teal-mid), var(--teal));\r\n  border-radius: 3px 0 0 3px;\r\n  opacity: 0.85;\r\n}\r\n.match-card--modern {\r\n  position: relative;\r\n  padding-left: 19px;\r\n}\r\n\r\n.match-card__top {\r\n  display: flex;\r\n  align-items: flex-start;\r\n  justify-content: space-between;\r\n  gap: 14px;\r\n  margin-bottom: 12px;\r\n}\r\n\r\n.match-identity {\r\n  display: flex;\r\n  align-items: flex-start;\r\n  gap: 12px;\r\n  min-width: 0;\r\n  flex: 1;\r\n}\r\n\r\n.match-avatar--lg {\r\n  width: 48px;\r\n  height: 48px;\r\n  font-size: 15px;\r\n  letter-spacing: -0.02em;\r\n}\r\n\r\n.match-name-row {\r\n  display: flex;\r\n  flex-wrap: wrap;\r\n  align-items: center;\r\n  gap: 8px;\r\n  margin-bottom: 2px;\r\n}\r\n.match-name {\r\n  margin: 0;\r\n  font-size: 15px;\r\n  font-weight: 600;\r\n  color: var(--text-main);\r\n  line-height: 1.3;\r\n}\r\n\r\n.niveau-pill {\r\n  font-size: 11px;\r\n  font-weight: 700;\r\n  text-transform: uppercase;\r\n  letter-spacing: 0.04em;\r\n  padding: 3px 9px;\r\n  border-radius: 999px;\r\n  border: 1px solid transparent;\r\n}\r\n.niveau-pill--excellent {\r\n  background: var(--teal-light);\r\n  color: var(--teal-dark);\r\n  border-color: rgba(29, 158, 117, 0.25);\r\n}\r\n.niveau-pill--bon {\r\n  background: var(--amber-bg);\r\n  color: var(--amber-text);\r\n  border-color: rgba(239, 159, 39, 0.35);\r\n}\r\n.niveau-pill--faible {\r\n  background: var(--danger-bg);\r\n  color: var(--danger-text);\r\n  border-color: var(--danger-border);\r\n}\r\n\r\n.match-score-block {\r\n  display: flex;\r\n  flex-direction: column;\r\n  align-items: center;\r\n  gap: 4px;\r\n  flex-shrink: 0;\r\n}\r\n\r\n.score-donut {\r\n  --accent: var(--teal);\r\n  --pct: 0%;\r\n  width: 58px;\r\n  height: 58px;\r\n  border-radius: 50%;\r\n  background: conic-gradient(var(--accent) var(--pct), #e2e8f0 0);\r\n  display: grid;\r\n  place-items: center;\r\n  box-shadow: inset 0 0 0 1px rgba(0, 0, 0, 0.04);\r\n}\r\n.score-donut__inner {\r\n  width: 44px;\r\n  height: 44px;\r\n  border-radius: 50%;\r\n  background: var(--bg-card);\r\n  display: flex;\r\n  flex-direction: row;\r\n  align-items: baseline;\r\n  justify-content: center;\r\n  gap: 1px;\r\n  padding-top: 2px;\r\n}\r\n.score-donut__value {\r\n  font-size: 14px;\r\n  font-weight: 700;\r\n  color: var(--text-main);\r\n  line-height: 1;\r\n}\r\n.score-donut__unit {\r\n  font-size: 10px;\r\n  font-weight: 700;\r\n  color: var(--text-muted);\r\n  line-height: 1;\r\n}\r\n\r\n.match-rank {\r\n  font-size: 11px;\r\n  font-weight: 600;\r\n  color: var(--text-muted);\r\n}\r\n\r\n.score-bar-wrap--tight {\r\n  margin-bottom: 12px;\r\n}\r\n\r\n.match-skills-grid {\r\n  display: grid;\r\n  grid-template-columns: 1fr 1fr;\r\n  gap: 12px 16px;\r\n  margin-bottom: 12px;\r\n}\r\n@media (max-width: 520px) {\r\n  .match-skills-grid {\r\n    grid-template-columns: 1fr;\r\n  }\r\n}\r\n\r\n.match-skills-label {\r\n  display: block;\r\n  font-size: 10px;\r\n  font-weight: 700;\r\n  text-transform: uppercase;\r\n  letter-spacing: 0.35px;\r\n  margin-bottom: 6px;\r\n}\r\n.match-skills-label--ok {\r\n  color: var(--teal-dark);\r\n}\r\n.match-skills-label--miss {\r\n  color: var(--danger-text);\r\n}\r\n\r\n.skill-tag--match {\r\n  background: var(--teal-light);\r\n  color: var(--teal-dark);\r\n  border: 1px solid rgba(29, 158, 117, 0.2);\r\n}\r\n.skill-tag--gap {\r\n  background: var(--danger-bg);\r\n  color: var(--danger-text);\r\n  border: 1px solid var(--danger-border);\r\n}\r\n\r\n.match-card__actions {\r\n  padding-top: 4px;\r\n  border-top: 1px solid var(--border);\r\n  margin-top: 2px;\r\n}\r\n\r\n/* \u2550\u2550\u2550 Layout 2 colonnes + IA \u2550\u2550\u2550 */\r\n.tm-layout {\r\n  display: grid;\r\n  grid-template-columns: minmax(0, 1fr) 340px;\r\n  gap: 24px;\r\n  align-items: start;\r\n}\r\n@media (max-width: 1024px) {\r\n  .tm-layout {\r\n    grid-template-columns: 1fr;\r\n  }\r\n  .tm-aside {\r\n    order: -1;\r\n  }\r\n}\r\n\r\n.tm-main {\r\n  min-width: 0;\r\n}\r\n\r\n.tm-chip--outline {\r\n  font-size: 11px !important;\r\n  color: var(--text-secondary) !important;\r\n}\r\n.tm-chip--outline code {\r\n  font-size: 10px;\r\n  background: var(--bg-surface);\r\n  padding: 2px 6px;\r\n  border-radius: 4px;\r\n}\r\n\r\n.tm-form-lead {\r\n  margin: 4px 0 0;\r\n  font-size: 13px;\r\n  color: var(--text-secondary);\r\n  line-height: 1.45;\r\n}\r\n\r\n.tm-textarea {\r\n  min-height: 88px;\r\n  resize: vertical;\r\n}\r\n\r\n.tm-metiers-block {\r\n  margin-bottom: 14px;\r\n}\r\n.tm-metiers-hint {\r\n  margin: 0 0 10px;\r\n}\r\n.tm-metier-chips {\r\n  display: flex;\r\n  flex-wrap: wrap;\r\n  gap: 8px;\r\n}\r\n.tm-metier-chip {\r\n  font-size: 12px;\r\n  font-weight: 600;\r\n  color: var(--text-secondary);\r\n  background: var(--bg-surface);\r\n  border: 1px solid var(--border);\r\n  border-radius: 999px;\r\n  padding: 6px 12px;\r\n  cursor: pointer;\r\n  transition: background 0.15s, border-color 0.15s, color 0.15s;\r\n}\r\n.tm-metier-chip:hover {\r\n  border-color: rgba(29, 158, 117, 0.35);\r\n  color: var(--teal-dark);\r\n}\r\n.tm-metier-chip--on {\r\n  background: var(--teal-light);\r\n  border-color: rgba(29, 158, 117, 0.45);\r\n  color: var(--teal-dark);\r\n}\r\n\r\n.tm-form-actions {\r\n  display: flex;\r\n  flex-wrap: wrap;\r\n  gap: 10px;\r\n  margin-top: 16px;\r\n}\r\n\r\n.tm-tabs-row {\r\n  display: flex;\r\n  flex-wrap: wrap;\r\n  align-items: center;\r\n  justify-content: space-between;\r\n  gap: 14px;\r\n  margin-bottom: 20px;\r\n}\r\n.tm-toolbar {\r\n  flex: 1;\r\n  min-width: 200px;\r\n  max-width: 420px;\r\n}\r\n.tm-search {\r\n  width: 100%;\r\n  padding: 10px 14px;\r\n  border-radius: 10px;\r\n  border: 1px solid var(--border);\r\n  font-size: 14px;\r\n  font-family: inherit;\r\n  background: var(--bg-card);\r\n  transition: border-color 0.15s, box-shadow 0.15s;\r\n}\r\n.tm-search:focus {\r\n  outline: none;\r\n  border-color: var(--teal);\r\n  box-shadow: 0 0 0 3px rgba(29, 158, 117, 0.12);\r\n}\r\n.tab-count {\r\n  opacity: 0.75;\r\n  font-weight: 600;\r\n}\r\n\r\n.tm-card-grid {\r\n  display: grid;\r\n  grid-template-columns: repeat(auto-fill, minmax(300px, 1fr));\r\n  gap: 16px;\r\n}\r\n.tm-talent-card .talent-header__body {\r\n  flex: 1;\r\n  min-width: 0;\r\n}\r\n.tm-profile-btn {\r\n  margin-top: 8px;\r\n}\r\n.tm-listing-startup {\r\n  margin-top: 4px !important;\r\n}\r\n.tm-listing-skills {\r\n  margin-top: 10px;\r\n}\r\n.tm-listing-loc {\r\n  font-size: 12px;\r\n  color: var(--text-muted);\r\n  margin: 8px 0 0;\r\n}\r\n.tm-listing-card--highlight {\r\n  outline: 2px solid var(--teal);\r\n  outline-offset: 2px;\r\n}\r\n.tm-empty {\r\n  grid-column: 1 / -1;\r\n  text-align: center;\r\n  padding: 28px;\r\n  color: var(--text-secondary);\r\n  font-size: 14px;\r\n}\r\n.tm-empty-wide {\r\n  grid-column: 1 / -1;\r\n  text-align: center;\r\n  padding: 28px;\r\n}\r\n\r\n/* Aside IA */\r\n.tm-aside {\r\n  position: sticky;\r\n  top: 88px;\r\n}\r\n.tm-ai-card {\r\n  border-radius: var(--radius-lg);\r\n  border: 1px solid rgba(29, 158, 117, 0.2);\r\n  background: linear-gradient(165deg, #ffffff 0%, #f0fdf9 55%, #f8fafc 100%);\r\n  padding: 20px;\r\n  box-shadow: var(--shadow-card);\r\n}\r\n.tm-ai-card__head {\r\n  display: flex;\r\n  gap: 12px;\r\n  align-items: flex-start;\r\n  margin-bottom: 12px;\r\n}\r\n.tm-ai-card__head h3 {\r\n  margin: 0;\r\n  font-size: 16px;\r\n  font-weight: 700;\r\n  color: var(--text-main);\r\n}\r\n.tm-ai-card__head p {\r\n  margin: 4px 0 0;\r\n  font-size: 11px;\r\n  color: var(--text-muted);\r\n  line-height: 1.4;\r\n}\r\n.tm-ai-icon {\r\n  font-size: 28px;\r\n  line-height: 1;\r\n}\r\n.tm-ai-intro {\r\n  font-size: 13px;\r\n  color: var(--text-secondary);\r\n  line-height: 1.55;\r\n  margin: 0 0 12px;\r\n}\r\n.tm-ai-label {\r\n  display: block;\r\n  font-size: 12px;\r\n  font-weight: 600;\r\n  color: var(--text-secondary);\r\n  margin-bottom: 6px;\r\n}\r\n.tm-ai-context {\r\n  margin-bottom: 12px;\r\n}\r\n.tm-ai-output {\r\n  margin-top: 18px;\r\n  padding-top: 16px;\r\n  border-top: 1px solid var(--border);\r\n  font-size: 13px;\r\n  color: var(--text-secondary);\r\n  line-height: 1.55;\r\n}\r\n.tm-ai-output h4 {\r\n  margin: 14px 0 6px;\r\n  font-size: 11px;\r\n  font-weight: 700;\r\n  text-transform: uppercase;\r\n  letter-spacing: 0.06em;\r\n  color: var(--teal-dark);\r\n}\r\n.tm-ai-output h4:first-child {\r\n  margin-top: 0;\r\n}\r\n.tm-ai-output ul {\r\n  margin: 0 0 0 18px;\r\n  padding: 0;\r\n}\r\n.tm-ai-output p {\r\n  margin: 0;\r\n}\r\n\r\n.modal-header__actions {\r\n  display: flex;\r\n  gap: 8px;\r\n  align-items: center;\r\n}\r\n.tm-meta-chip {\r\n  font-size: 13px;\r\n  color: var(--text-secondary);\r\n}\r\n.tm-modal-divider {\r\n  border-top: 1px solid var(--border);\r\n  margin: 0 22px;\r\n}\r\n.tm-modal-skills {\r\n  margin-top: 12px;\r\n}\r\n.tm-section-label {\r\n  font-size: 12px;\r\n  font-weight: 600;\r\n  color: var(--text-secondary);\r\n  text-transform: uppercase;\r\n  letter-spacing: 0.3px;\r\n  margin-bottom: 7px;\r\n}\r\n.matching-toolbar {\r\n  display: flex;\r\n  align-items: center;\r\n  gap: 12px;\r\n  flex-wrap: wrap;\r\n}\r\n.tm-sort-label {\r\n  display: flex;\r\n  align-items: center;\r\n 